// ✅ Enhanced Final Success Summary with Complete Campaign Data
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      success: false,
      message: 'No leads were updated in Airtable',
      telegram_message: '❌ *Lead Selection Failed*\n\nNo leads were processed. Please check the workflow configuration.',
      timestamp: new Date().toISOString()
    }
  }];
}

// This node should receive the SUMMARY object from the "Filter Summary Only" node
const summaryData = items[0].json;

// Check if this is actually the summary object
if (!summaryData.selection_complete) {
  return [{
    json: {
      success: false,
      message: 'Invalid data received - expected summary object',
      telegram_message: '❌ *Configuration Error*\n\nSummary node received lead data instead of summary. Please check filter configuration.',
      timestamp: new Date().toISOString()
    }
  }];
}

const timestamp = new Date().toISOString();

// Extract comprehensive data from the summary object
const stats = summaryData.score_range;
const quality = summaryData.quality_distribution;
const industry = summaryData.industry_relevance_stats;
const outcomes = summaryData.recommendation_summary?.expected_outcomes;
const niche = summaryData.niche_context;

// Create detailed Telegram message
const telegramMessage = `🎯 *Lead Selection Campaign Complete!*\n\n` +
  `${summaryData.strategy_emoji} *${summaryData.strategy_used}*\n` +
  `✅ *Successfully Selected: ${summaryData.leads_selected} Premium Leads*\n` +
  `📊 *Analyzed: ${summaryData.total_leads_analyzed} Total Prospects*\n\n` +

  `*🎯 Campaign Overview:*\n` +
  `• Selection Accuracy: ${summaryData.selection_accuracy}\n` +
  `• Quality Score: ${stats.highest}-${stats.lowest} (avg: ${stats.average})\n` +
  `• Premium Leads: ${quality.premium_leads}/${summaryData.leads_selected}\n` +
  `• C-Level Contacts: ${summaryData.c_level_contacts}\n` +
  `• Funded Companies: ${summaryData.funded_companies}\n\n` +

  `*🏢 Industry & Niche Focus:*\n` +
  `• Target Industry: ${niche.target_industry}\n` +
  `• Service Focus: ${niche.outreach_focus}\n` +
  `• Service Offering: ${niche.service_offering}\n` +
  `• Avg Industry Relevance: ${industry.avg_relevance}%\n` +
  `• Perfect Matches: ${industry.perfect_matches}\n\n` +

  `*📈 Lead Quality Breakdown:*\n` +
  `• Top Industries: ${industry.top_industries.slice(0, 2).join(', ')}\n` +
  `• High Confidence Emails: ${summaryData.high_confidence_emails || 0}\n` +
  `• All C-Level Decision Makers: ${summaryData.c_level_contacts}\n\n` +

  `*🎯 Airtable Processing:*\n` +
  `• Status: ✅ Complete\n` +
  `• Priority: 🔥 High\n` +
  `• Quality: ⭐ High\n` +
  `• Enrichment Ready: 🚀 Yes\n\n` +

  `*📊 Campaign Projections:*\n` +
  `• Expected Response Rate: ${summaryData.predicted_response_rate}\n` +
  `• Projected Meetings: ~${outcomes?.expected_meetings || Math.round(summaryData.leads_selected * 0.2)}\n` +
  `• Budget Estimate: ${summaryData.recommendation_summary?.budget_estimate || '$60-90'}\n` +
  `• Timeline: ${summaryData.recommendation_summary?.timeline || '1-2 weeks'}\n\n` +

  `*🚀 Next Steps:*\n` +
  `• LinkedIn + AI enrichment pipeline\n` +
  `• Personalized message generation\n` +
  `• Multi-channel outreach setup\n` +
  `• Campaign performance tracking\n\n` +

  `*Campaign ID:* ${summaryData.timestamp.slice(-8)}\n` +
  `*Completed:* ${new Date().toLocaleString()}\n` +
  `*Status:* Ready for Enrichment Pipeline ✨`;

const finalSummary = {
  success: true,
  leads_updated: summaryData.leads_selected,
  campaign_overview: {
    strategy: summaryData.strategy_used,
    strategy_emoji: summaryData.strategy_emoji,
    total_analyzed: summaryData.total_leads_analyzed,
    leads_selected: summaryData.leads_selected,
    selection_accuracy: summaryData.selection_accuracy,
    predicted_response_rate: summaryData.predicted_response_rate
  },
  quality_metrics: {
    score_range: stats,
    quality_distribution: quality,
    c_level_contacts: summaryData.c_level_contacts,
    funded_companies: summaryData.funded_companies,
    high_confidence_emails: summaryData.high_confidence_emails || 0
  },
  niche_targeting: {
    target_industry: niche.target_industry,
    outreach_focus: niche.outreach_focus,
    service_offering: niche.service_offering,
    industry_relevance: industry.avg_relevance,
    perfect_matches: industry.perfect_matches,
    top_industries: industry.top_industries
  },
  campaign_projections: {
    expected_response_rate: summaryData.predicted_response_rate,
    expected_meetings: outcomes?.expected_meetings || Math.round(summaryData.leads_selected * 0.2),
    budget_estimate: summaryData.recommendation_summary?.budget_estimate || '$60-90',
    timeline: summaryData.recommendation_summary?.timeline || '1-2 weeks'
  },
  airtable_fields_updated: [
    'Processing Status',
    'Outreach Priority',
    'Data Quality', 
    'Ready for Outreach',
    'Target Industry',
    'Service Offering'
  ],
  telegram_message: telegramMessage,
  next_phase: 'enrichment_pipeline',
  timestamp: timestamp,
  message: `Successfully selected and marked ${summaryData.leads_selected} premium leads using ${summaryData.strategy_used}`,
  ready_for_next_workflow: true
};

console.log(`✅ Campaign Summary: ${summaryData.leads_selected} leads selected`);
console.log(`📊 Strategy: ${summaryData.strategy_used}`);
console.log(`🎯 Score range: ${stats.highest} to ${stats.lowest} (avg: ${stats.average})`);
console.log(`🎯 Ready for enrichment pipeline`);

return [{ json: finalSummary }];

// 🎯 UNIVERSAL Smart Lead Scoring & Selection - ANY USER INPUT COMPATIBLE
const items = $input.all();

// Validate input data
if (!items || items.length === 0) {
  return [{
    json: {
      error: 'No input data received',
      suggestion: 'Check if Airtable fetch is providing lead data',
      timestamp: new Date().toISOString()
    }
  }];
}

console.log('🔍 Received items count:', items.length);
console.log('🔍 First item structure:', Object.keys(items[0].json || {}));

// 🔧 Get recommendation data from previous node reference
let recommendation, userPreferences, nicheContext;

try {
  const recommendationNode = $('🧠 Intelligent Recommendation Engine');
  if (recommendationNode && recommendationNode.first()) {
    const recData = recommendationNode.first().json;
    recommendation = recData.recommendation;
    userPreferences = recData.user_preferences;
    nicheContext = recData.niche_context;
    console.log('✅ Found recommendation data from node reference');
  }
} catch (error) {
  console.log('⚠️ Could not access recommendation node, using defaults');
}

// 🔧 FALLBACK: Create default recommendation if not available
if (!recommendation) {
  console.log('🔄 Creating fallback recommendation strategy');

  recommendation = {
    strategy_name: 'Universal Lead Selection',
    strategy_emoji: '🎯',
    lead_count: 15,
    scoring_weights: {
      industry_relevance: 40,
      email_verification: 25,
      company_size: 15,
      seniority_level: 15,
      funding_stage: 5
    },
    expected_outcomes: {
      response_rate: '15-25%',
      meeting_conversion: '45-65%'
    },
    success_probability: 80
  };

  userPreferences = {
    campaign_objective: 'Strategic Growth',
    risk_tolerance: 'Balanced',
    lead_quantity: '🧪 Pilot Test (15 leads) - $30-45 budget'
  };

  nicheContext = {
    service_offering: 'business services',
    outreach_focus: 'General Business Development',
    target_industry: 'technology'
  };
}

// 🎯 ENHANCED: Extract exact target lead count from user form
let targetLeadCount = recommendation.lead_count || 15;

// Try multiple methods to get the exact count the user selected
if (userPreferences && userPreferences.lead_quantity) {
  const leadQuantityText = userPreferences.lead_quantity || '';
  console.log('📊 Raw lead quantity text:', leadQuantityText);

  // Enhanced regex patterns to catch all formats
  const patterns = [
    /\((\d+)\s+leads?\)/i,           // (15 leads)
    /(\d+)\s+leads?/i,               // 15 leads
    /pilot.*?(\d+)/i,                // Pilot Test 15
    /quick.*?(\d+)/i,                // Quick Start 30
    /standard.*?(\d+)/i,             // Standard 50
    /premium.*?(\d+)/i               // Premium 75
  ];

  for (const pattern of patterns) {
    const match = leadQuantityText.match(pattern);
    if (match) {
      targetLeadCount = parseInt(match[1]);
      console.log(`✅ Extracted lead count: ${targetLeadCount} using pattern: ${pattern}`);
      break;
    }
  }

  // Fallback: Check for common numbers in the text
  if (!targetLeadCount || targetLeadCount === 15) {
    if (leadQuantityText.includes('30')) targetLeadCount = 30;
    else if (leadQuantityText.includes('50')) targetLeadCount = 50;
    else if (leadQuantityText.includes('75')) targetLeadCount = 75;
    else if (leadQuantityText.includes('100')) targetLeadCount = 100;
  }
}

console.log('🎯 FINAL TARGET LEAD COUNT:', targetLeadCount);

// Process all items as leads
const leads = items;

if (!leads || leads.length === 0) {
  return [{
    json: {
      error: 'No leads found in Airtable data',
      suggestion: 'Check Airtable filter and ensure leads exist',
      recommendation: recommendation,
      timestamp: new Date().toISOString()
    }
  }];
}

console.log(`🎯 Scoring ${leads.length} leads to select TOP ${targetLeadCount} using ${recommendation.strategy_name}`);

const scoredLeads = [];
const weights = recommendation.scoring_weights || {};

// 🔧 UNIVERSAL Industry Relevance Scoring Function
function calculateIndustryRelevance(companyIndustry, nicheContext) {
  const industry = (companyIndustry || '').toLowerCase();
  const service = (nicheContext.service_offering || '').toLowerCase();
  const focus = (nicheContext.outreach_focus || '').toLowerCase();
  const target = (nicheContext.target_industry || '').toLowerCase();

  let relevanceScore = 0;

  console.log(`🔍 Analyzing industry: "${industry}" for service: "${service}"`);

  // 🤖 AI & AUTOMATION PERFECT MATCHES
  if (service.includes('ai') || service.includes('automation')) {
    if (industry.includes('manufacturing') || industry.includes('logistics')) {
      relevanceScore = 100; // Perfect match - high automation potential
    } else if (industry.includes('healthcare') || industry.includes('financial')) {
      relevanceScore = 95; // Excellent match - process-heavy industries
    } else if (industry.includes('software') || industry.includes('technology')) {
      relevanceScore = 90; // Great match - tech-forward companies
    } else if (industry.includes('consulting') || industry.includes('professional services')) {
      relevanceScore = 85; // Good match - process optimization needs
    }
  }

  // 📈 LEAD GENERATION PERFECT MATCHES
  if (service.includes('lead') || service.includes('marketing') || service.includes('sales')) {
    if (industry.includes('real estate')) {
      relevanceScore = Math.max(relevanceScore, 100); // Perfect - lead-dependent industry
    } else if (industry.includes('insurance') || industry.includes('financial services')) {
      relevanceScore = Math.max(relevanceScore, 95); // Excellent - client acquisition focused
    } else if (industry.includes('marketing') || industry.includes('advertising')) {
      relevanceScore = Math.max(relevanceScore, 92); // Excellent - they understand the value
    } else if (industry.includes('consulting') || industry.includes('professional services')) {
      relevanceScore = Math.max(relevanceScore, 88); // Great - always need new clients
    } else if (industry.includes('software') || industry.includes('technology')) {
      relevanceScore = Math.max(relevanceScore, 85); // Good - growth-focused
    }
  }

  // 📄 DOCUMENT PROCESSING PERFECT MATCHES
  if (service.includes('document') || service.includes('data') || focus.includes('document')) {
    if (industry.includes('legal')) {
      relevanceScore = Math.max(relevanceScore, 98); // Perfect - document-heavy
    } else if (industry.includes('healthcare') || industry.includes('medical')) {
      relevanceScore = Math.max(relevanceScore, 95); // Excellent - lots of paperwork
    } else if (industry.includes('financial') || industry.includes('accounting')) {
      relevanceScore = Math.max(relevanceScore, 92); // Excellent - compliance heavy
    } else if (industry.includes('insurance')) {
      relevanceScore = Math.max(relevanceScore, 90); // Great - claims processing
    } else if (industry.includes('government') || industry.includes('education')) {
      relevanceScore = Math.max(relevanceScore, 85); // Good - bureaucratic processes
    }
  }

  // 🎯 TARGET INDUSTRY SPECIFIC MATCHING
  if (target) {
    // Direct industry name matching
    if (industry.includes(target) || target.includes(industry)) {
      relevanceScore = Math.max(relevanceScore, 95);
      console.log('🎯 Direct target industry match found!');
    }

    // Dental/Healthcare specific
    if (target.includes('dental') || target.includes('dentist')) {
      if (industry.includes('dental') || industry.includes('healthcare') || industry.includes('medical')) {
        relevanceScore = Math.max(relevanceScore, 100);
      }
    }

    // E-commerce specific
    if (target.includes('ecommerce') || target.includes('retail')) {
      if (industry.includes('retail') || industry.includes('e-commerce') || industry.includes('consumer')) {
        relevanceScore = Math.max(relevanceScore, 95);
      }
    }

    // SaaS/Tech specific
    if (target.includes('saas') || target.includes('software')) {
      if (industry.includes('software') || industry.includes('technology') || industry.includes('saas')) {
        relevanceScore = Math.max(relevanceScore, 95);
      }
    }
  }

  // 🎯 BONUS POINTS for high-growth industries
  if (industry.includes('saas') || industry.includes('fintech') || industry.includes('ai') || 
      industry.includes('blockchain') || industry.includes('cybersecurity')) {
    relevanceScore += 10;
  }

  // Base alignment scores for common industries
  if (relevanceScore === 0) {
    if (industry.includes('information technology') || industry.includes('software')) {
      relevanceScore = 75;
    } else if (industry.includes('professional services') || industry.includes('consulting')) {
      relevanceScore = 70;
    } else if (industry.includes('business services')) {
      relevanceScore = 65;
    } else {
      relevanceScore = 50; // Base score for any business
    }
  }

  return Math.min(relevanceScore, 100);
}

// 🏆 ENHANCED Lead Quality Assessment
function assessLeadQuality(lead) {
  let qualityScore = 0;
  const qualityFactors = {};

  // Email quality (critical for outreach)
  const emailConfidence = parseInt(lead['Email Confidence'] || 0);
  if (emailConfidence >= 90) {
    qualityScore += 25;
    qualityFactors.email = 'excellent';
  } else if (emailConfidence >= 75) {
    qualityScore += 20;
    qualityFactors.email = 'good';
  } else if (emailConfidence >= 50) {
    qualityScore += 10;
    qualityFactors.email = 'fair';
  } else {
    qualityFactors.email = 'poor';
  }

  // Seniority level (decision makers)
  const seniority = lead['Seniority Level'];
  if (seniority === 'C-Level') {
    qualityScore += 25;
    qualityFactors.seniority = 'c-level';
  } else if (seniority === 'VP') {
    qualityScore += 20;
    qualityFactors.seniority = 'vp';
  } else if (seniority === 'Director') {
    qualityScore += 15;
    qualityFactors.seniority = 'director';
  } else if (seniority === 'Manager') {
    qualityScore += 10;
    qualityFactors.seniority = 'manager';
  }

  // Company size sweet spot
  const companySize = parseInt(lead['Company Size'] || 0);
  if (companySize >= 11 && companySize <= 200) {
    qualityScore += 20; // Sweet spot for responsiveness and budget
    qualityFactors.size = 'ideal';
  } else if (companySize >= 201 && companySize <= 1000) {
    qualityScore += 15;
    qualityFactors.size = 'good';
  } else if (companySize >= 1 && companySize <= 10) {
    qualityScore += 10;
    qualityFactors.size = 'small';
  }

  // LinkedIn presence
  if (lead['Personal LinkedIn URL'] && lead['Personal LinkedIn URL'] !== '') {
    qualityScore += 10;
    qualityFactors.linkedin = 'present';
  }

  // Company revenue indicator
  const revenue = parseFloat(lead['Company Revenue'] || 0);
  if (revenue > 10000000) {
    qualityScore += 15;
    qualityFactors.revenue = 'high';
  } else if (revenue > 1000000) {
    qualityScore += 10;
    qualityFactors.revenue = 'medium';
  }

  // Funding status (growth indicator)
  const fundingStatus = lead['Funding Status'];
  if (['Series A', 'Series B', 'Series C+'].includes(fundingStatus)) {
    qualityScore += 15;
    qualityFactors.funding = 'funded';
  } else if (fundingStatus === 'Seed') {
    qualityScore += 10;
    qualityFactors.funding = 'seed';
  }

  return { qualityScore, qualityFactors };
}

// Score each lead with enhanced algorithm
for (const item of leads) {
  const lead = item.json.fields || item.json;
  let totalScore = 0;
  const scoreBreakdown = {};

  // 🎯 Industry Relevance (40% weight)
  const industryScore = calculateIndustryRelevance(lead['Company Industry'], nicheContext);
  const industryWeight = (industryScore / 100) * (weights.industry_relevance || 40);
  totalScore += industryWeight;
  scoreBreakdown.industry_relevance = industryWeight;
  scoreBreakdown.industry_relevance_raw = industryScore;

  // 🏆 Lead Quality Assessment (25% weight)
  const qualityAssessment = assessLeadQuality(lead);
  const qualityWeight = (qualityAssessment.qualityScore / 100) * (weights.email_verification || 25);
  totalScore += qualityWeight;
  scoreBreakdown.lead_quality = qualityWeight;
  scoreBreakdown.quality_factors = qualityAssessment.qualityFactors;

  // 🏢 Company Size Optimization (15% weight)
  const companySize = parseInt(lead['Company Size'] || 0);
  let sizeScore = 0;
  if (companySize >= 11 && companySize <= 50) {
    sizeScore = 100; // Perfect size for responsiveness
  } else if (companySize >= 51 && companySize <= 200) {
    sizeScore = 85; // Good size with budget
  } else if (companySize >= 201 && companySize <= 500) {
    sizeScore = 70; // Larger but may be slower
  } else if (companySize >= 1 && companySize <= 10) {
    sizeScore = 60; // Small but may lack budget
  }
  const sizeWeight = (sizeScore / 100) * (weights.company_size || 15);
  totalScore += sizeWeight;
  scoreBreakdown.company_size = sizeWeight;

  // 👑 Seniority Level (15% weight)
  const seniority = lead['Seniority Level'];
  let seniorityScore = 0;
  if (seniority === 'C-Level') seniorityScore = 100;
  else if (seniority === 'VP') seniorityScore = 85;
  else if (seniority === 'Director') seniorityScore = 70;
  else if (seniority === 'Manager') seniorityScore = 55;
  else seniorityScore = 30;

  const seniorityWeight = (seniorityScore / 100) * (weights.seniority_level || 15);
  totalScore += seniorityWeight;
  scoreBreakdown.seniority = seniorityWeight;

  // 💰 Funding/Revenue Bonus (5% weight)
  const revenue = parseFloat(lead['Company Revenue'] || 0);
  const fundingStatus = lead['Funding Status'];
  let financialScore = 0;

  if (revenue > 50000000 || ['Series B', 'Series C+'].includes(fundingStatus)) {
    financialScore = 100;
  } else if (revenue > 10000000 || fundingStatus === 'Series A') {
    financialScore = 80;
  } else if (revenue > 1000000 || fundingStatus === 'Seed') {
    financialScore = 60;
  } else if (fundingStatus === 'Private') {
    financialScore = 40;
  }

  const financialWeight = (financialScore / 100) * (weights.funding_stage || 5);
  totalScore += financialWeight;
  scoreBreakdown.financial = financialWeight;

  // 🎯 BONUS MULTIPLIERS for exceptional leads
  let bonusMultiplier = 1.0;

  // Perfect lead bonus
  if (industryScore >= 95 && qualityAssessment.qualityScore >= 80) {
    bonusMultiplier = 1.15; // 15% bonus for perfect leads
    scoreBreakdown.perfect_lead_bonus = true;
  }

  // High-confidence email + C-Level combo
  if (parseInt(lead['Email Confidence'] || 0) >= 85 && seniority === 'C-Level') {
    bonusMultiplier = Math.max(bonusMultiplier, 1.10);
    scoreBreakdown.premium_contact_bonus = true;
  }

  // Apply bonus multiplier
  totalScore *= bonusMultiplier;
  scoreBreakdown.bonus_multiplier = bonusMultiplier;

  // Add scored lead to array
  scoredLeads.push({
    json: {
      ...lead,
      selection_score: Math.round(totalScore),
      industry_relevance_score: industryScore,
      lead_quality_score: qualityAssessment.qualityScore,
      score_breakdown: scoreBreakdown,
      selection_strategy: recommendation.strategy_name,
      selection_timestamp: new Date().toISOString(),
      user_campaign_objective: userPreferences.campaign_objective || 'Unknown',
      expected_response_rate: recommendation.expected_outcomes ? recommendation.expected_outcomes.response_rate : 'Unknown',
      niche_match: nicheContext,
      ready_for_enrichment: true,
      processing_priority: totalScore >= 85 ? 'urgent' : totalScore >= 70 ? 'high' : totalScore >= 50 ? 'medium' : 'low',
      lead_tier: totalScore >= 90 ? 'premium' : totalScore >= 75 ? 'gold' : totalScore >= 60 ? 'silver' : 'bronze'
    }
  });
}

// 🏆 Sort by score (highest first) - This ensures we get the BEST leads
scoredLeads.sort((a, b) => b.json.selection_score - a.json.selection_score);

// 🎯 Select EXACTLY the number of leads requested
const selectedLeads = scoredLeads.slice(0, targetLeadCount);

console.log(`🏆 SELECTED EXACTLY ${selectedLeads.length} LEADS from ${leads.length} candidates (REQUESTED: ${targetLeadCount})`);
console.log(`🎯 Score range: ${selectedLeads[0]?.json.selection_score} (best) to ${selectedLeads[selectedLeads.length - 1]?.json.selection_score} (lowest selected)`);
console.log(`📊 Average score of selected leads: ${selectedLeads.length > 0 ? Math.round(selectedLeads.reduce((sum, lead) => sum + lead.json.selection_score, 0) / selectedLeads.length) : 0}`);

// Show quality distribution
const premiumCount = selectedLeads.filter(lead => lead.json.lead_tier === 'premium').length;
const goldCount = selectedLeads.filter(lead => lead.json.lead_tier === 'gold').length;
const silverCount = selectedLeads.filter(lead => lead.json.lead_tier === 'silver').length;

console.log(`🏆 Quality distribution: ${premiumCount} Premium, ${goldCount} Gold, ${silverCount} Silver`);

// Generate comprehensive final summary
const finalSummary = {
  json: {
    selection_complete: true,
    strategy_used: recommendation.strategy_name,
    strategy_emoji: recommendation.strategy_emoji || '🎯',

    // EXACT COUNTS
    total_leads_analyzed: leads.length,
    leads_selected: selectedLeads.length,
    requested_lead_count: targetLeadCount,
    selection_accuracy: selectedLeads.length === targetLeadCount ? 'PERFECT' : 'PARTIAL',

    // QUALITY METRICS
    score_range: {
      highest: selectedLeads[0]?.json.selection_score || 0,
      lowest: selectedLeads[selectedLeads.length - 1]?.json.selection_score || 0,
      average: selectedLeads.length > 0 ? Math.round(selectedLeads.reduce((sum, lead) => sum + lead.json.selection_score, 0) / selectedLeads.length) : 0
    },

    // QUALITY DISTRIBUTION
    quality_distribution: {
      premium_leads: premiumCount,
      gold_leads: goldCount,
      silver_leads: silverCount,
      bronze_leads: selectedLeads.filter(lead => lead.json.lead_tier === 'bronze').length
    },

    // INDUSTRY RELEVANCE
    industry_relevance_stats: {
      avg_relevance: selectedLeads.length > 0 ? Math.round(selectedLeads.reduce((sum, lead) => sum + lead.json.industry_relevance_score, 0) / selectedLeads.length) : 0,
      perfect_matches: selectedLeads.filter(lead => lead.json.industry_relevance_score >= 95).length,
      high_relevance_count: selectedLeads.filter(lead => lead.json.industry_relevance_score >= 80).length,
      top_industries: [...new Set(selectedLeads.slice(0, 10).map(lead => lead.json['Company Industry']))]
    },

    // CAMPAIGN READINESS
    high_confidence_emails: selectedLeads.filter(lead => parseInt(lead.json['Email Confidence'] || 0) >= 85).length,
    c_level_contacts: selectedLeads.filter(lead => lead.json['Seniority Level'] === 'C-Level').length,
    funded_companies: selectedLeads.filter(lead => ['Seed', 'Series A', 'Series B', 'Series C+'].includes(lead.json['Funding Status'])).length,

    niche_context: nicheContext,
    recommendation_summary: recommendation,
    user_preferences: userPreferences,
    ready_for_enrichment: true,
    timestamp: new Date().toISOString(),

    // SUCCESS PREDICTION
    predicted_response_rate: selectedLeads.length > 0 ? 
      Math.round(selectedLeads.reduce((sum, lead) => sum + lead.json.selection_score, 0) / selectedLeads.length / 100 * 25) + '%' : '0%'
  }
};

console.log('✅ UNIVERSAL SELECTION COMPLETE!');
console.log(`🎯 Delivered exactly ${targetLeadCount} leads as requested`);
console.log(`🏆 Average quality score: ${finalSummary.json.score_range.average}/100`);
console.log(`📧 High-confidence emails: ${finalSummary.json.high_confidence_emails}/${selectedLeads.length}`);

// Return selected leads + comprehensive summary
return [...selectedLeads, finalSummary];

// 🧠 Universal Intelligent Recommendation Engine - Dynamic User Input Handler
const formData = $json;

