// 🔧 UNIVERSAL Industry Matching Logic - Handles ANY User Input
function getRelevantIndustries(serviceOffering, outreachFocus, targetIndustry) {
  const relevantIndustries = [];
  const service = (serviceOffering || '').toLowerCase();
  const focus = (outreachFocus || '').toLowerCase();
  const target = (targetIndustry || '').toLowerCase();

  console.log('🎯 Analyzing service patterns:', { service, focus, target });

  // 🤖 AI & AUTOMATION SERVICES
  if (service.includes('ai') || service.includes('automation') || service.includes('artificial intelligence')) {
    relevantIndustries.push(
      'information technology & services', 'software', 'computer software',
      'manufacturing', 'healthcare', 'financial services', 'consulting',
      'business services', 'logistics & supply chain', 'retail'
    );
  }

  // 📈 LEAD GENERATION & SALES SERVICES
  if (service.includes('lead') || service.includes('marketing') || service.includes('sales') || service.includes('outreach')) {
    relevantIndustries.push(
      'real estate', 'insurance', 'financial services', 'marketing & advertising',
      'consulting', 'professional services', 'software', 'business services',
      'education', 'healthcare', 'automotive', 'construction'
    );
  }

  // 📄 DOCUMENT PROCESSING & DATA SERVICES
  if (service.includes('document') || service.includes('data entry') || service.includes('processing') || 
      focus.includes('document') || focus.includes('data') || focus.includes('processing')) {
    relevantIndustries.push(
      'legal services', 'healthcare', 'financial services', 'insurance',
      'accounting', 'government', 'education', 'real estate', 'consulting'
    );
  }

  // 📧 EMAIL & COMMUNICATION SERVICES
  if (service.includes('email') || service.includes('communication') || service.includes('messaging')) {
    relevantIndustries.push(
      'marketing & advertising', 'professional services', 'consulting',
      'software', 'business services', 'education', 'healthcare', 'retail'
    );
  }

  // 🛒 E-COMMERCE & RETAIL FOCUS
  if (target.includes('ecommerce') || target.includes('e-commerce') || target.includes('retail') || 
      target.includes('online') || target.includes('shop')) {
    relevantIndustries.push(
      'retail', 'e-commerce', 'consumer goods', 'food & beverages',
      'wholesale', 'apparel & fashion', 'sporting goods', 'furniture'
    );
  }

  // 🏥 HEALTHCARE FOCUS
  if (target.includes('healthcare') || target.includes('medical') || target.includes('dental') || 
      target.includes('doctor') || target.includes('clinic') || target.includes('dentist')) {
    relevantIndustries.push(
      'healthcare', 'medical practice', 'pharmaceuticals', 'medical devices',
      'biotechnology', 'veterinary', 'mental health care'
    );
  }

  // 🏠 REAL ESTATE FOCUS
  if (target.includes('real estate') || target.includes('property') || target.includes('realty') || 
      target.includes('mortgage') || target.includes('construction')) {
    relevantIndustries.push(
      'real estate', 'construction', 'architecture & planning',
      'building materials', 'mortgage', 'property management'
    );
  }

  // 💰 FINANCIAL SERVICES FOCUS
  if (target.includes('financial') || target.includes('finance') || target.includes('accounting') || 
      target.includes('insurance') || target.includes('banking')) {
    relevantIndustries.push(
      'financial services', 'banking', 'insurance', 'accounting',
      'investment management', 'venture capital & private equity'
    );
  }

  // ⚖️ LEGAL SERVICES FOCUS
  if (target.includes('legal') || target.includes('law') || target.includes('attorney') || target.includes('lawyer')) {
    relevantIndustries.push(
      'legal services', 'law practice', 'government administration'
    );
  }

  // 💻 TECHNOLOGY & SOFTWARE FOCUS
  if (target.includes('tech') || target.includes('software') || target.includes('saas') || 
      target.includes('it') || target.includes('digital') || target.includes('app')) {
    relevantIndustries.push(
      'information technology & services', 'software', 'computer software',
      'internet', 'telecommunications', 'computer hardware'
    );
  }

  // 🎓 EDUCATION FOCUS
  if (target.includes('education') || target.includes('school') || target.includes('university') || 
      target.includes('training') || target.includes('learning')) {
    relevantIndustries.push(
      'education', 'higher education', 'e-learning', 'primary/secondary education'
    );
  }

  // 🏭 MANUFACTURING & INDUSTRIAL FOCUS
  if (target.includes('manufacturing') || target.includes('industrial') || target.includes('factory') || 
      target.includes('production') || target.includes('automotive')) {
    relevantIndustries.push(
      'manufacturing', 'automotive', 'industrial automation',
      'machinery', 'chemicals', 'metals and mining'
    );
  }

  // 🍔 FOOD & RESTAURANT FOCUS
  if (target.includes('food') || target.includes('restaurant') || target.includes('hospitality') || 
      target.includes('hotel') || target.includes('catering')) {
