// Build intelligent filter
function buildIntelligentFilter(preferences, serviceOffering, outreachFocus, targetIndustry) {
  const filterConditions = [];

  // Base conditions
  filterConditions.push('{Processing Status} = "apollo_complete"');
  filterConditions.push('{Ready for Enrichment} != TRUE()');

  // 🎯 Smart Industry Filtering
  const relevantIndustries = getRelevantIndustries(serviceOffering, outreachFocus, targetIndustry);

  if (relevantIndustries.length > 0) {
    const industryConditions = relevantIndustries.map(industry => 
      `FIND("${industry}", LOWER({Company Industry})) > 0`
    );

    // Add keyword matching for broader coverage
    const keywordConditions = [];

    if (serviceOffering.toLowerCase().includes('lead')) {
      keywordConditions.push(
        'FIND("marketing", LOWER({Company Industry})) > 0',
        'FIND("advertising", LOWER({Company Industry})) > 0',
        'FIND("consulting", LOWER({Company Industry})) > 0'
      );
    }

    if (outreachFocus.toLowerCase().includes('document')) {
      keywordConditions.push(
        'FIND("legal", LOWER({Company Industry})) > 0',
        'FIND("financial", LOWER({Company Industry})) > 0',
        'FIND("healthcare", LOWER({Company Industry})) > 0'
      );
    }

    const allIndustryConditions = [...industryConditions, ...keywordConditions];

    if (allIndustryConditions.length > 0) {
      filterConditions.push(`OR(${allIndustryConditions.join(', ')})`);
      console.log('🎯 Added industry filtering for:', relevantIndustries.join(', '));
    }
  }

  // Other filter conditions
  if (preferences.contact_method_preference && preferences.contact_method_preference.includes('Email Focused')) {
    filterConditions.push('{Email Confidence} >= 75');
  } else if (preferences.contact_method_preference && preferences.contact_method_preference.includes('LinkedIn Focused')) {
    filterConditions.push('{Personal LinkedIn URL} != ""');
  }

  if (preferences.company_size_preference && preferences.company_size_preference.includes('Startup Focused')) {
    filterConditions.push('AND({Company Size} >= 11, {Company Size} <= 50)');
  } else if (preferences.company_size_preference && preferences.company_size_preference.includes('Growth Stage')) {
    filterConditions.push('AND({Company Size} >= 51, {Company Size} <= 200)');
  }

  if (preferences.funding_preference && preferences.funding_preference.includes('Recently Funded')) {
    filterConditions.push('OR({Funding Status} = "Seed", {Funding Status} = "Series A")');
  } else if (preferences.funding_preference && preferences.funding_preference.includes('Bootstrapped')) {
    filterConditions.push('{Funding Status} = "Private"');
  }

  if (preferences.seniority_preference && preferences.seniority_preference.includes('C-Level Only')) {
    filterConditions.push('{Seniority Level} = "C-Level"');
  } else if (preferences.seniority_preference && preferences.seniority_preference.includes('Senior Leadership')) {
    filterConditions.push('OR({Seniority Level} = "C-Level", {Seniority Level} = "VP")');
  }

  return `AND(${filterConditions.join(', ')})`;
}

